pub fn sys_execve(
    uctx: &mut UserContext,
    path: *const c_char,
    argv: *const *const c_char,
    envp: *const *const c_char,
) -> AxResult<isize> {
    let path = vm_load_string(path)?;

    let args = if argv.is_null() {
        Vec::new()
    } else {
        vm_load_until_nul(argv)?
            .into_iter()
            .map(vm_load_string)
            .collect::<Result<Vec<_>, _>>()?
    };

    let envs = if envp.is_null() {
        Vec::new()
    } else {
        vm_load_until_nul(envp)?
            .into_iter()
            .map(vm_load_string)
            .collect::<Result<Vec<_>, _>>()?
    };

    debug!("sys_execve <= path: {path:?}, args: {args:?}, envs: {envs:?}");

    do_execve(uctx, &path, args, envs)
}

/// execveat syscall - execute program relative to a directory file descriptor
///
/// # Arguments
/// - `dirfd`: Directory file descriptor (AT_FDCWD = -100 for current directory)
/// - `pathname`: Path to the program
/// - `argv`: Argument array
/// - `envp`: Environment array
/// - `flags`: Currently only AT_EMPTY_PATH (0x1000) is supported
pub fn sys_execveat(
    uctx: &mut UserContext,
    dirfd: i32,
    pathname: *const c_char,
    argv: *const *const c_char,
    envp: *const *const c_char,
    flags: u32,
) -> AxResult<isize> {
    let path = vm_load_string(pathname)?;

    let args = if argv.is_null() {
        Vec::new()
    } else {
        vm_load_until_nul(argv)?
            .into_iter()
            .map(vm_load_string)
            .collect::<Result<Vec<_>, _>>()?
    };

    let envs = if envp.is_null() {
        Vec::new()
    } else {
        vm_load_until_nul(envp)?
            .into_iter()
            .map(vm_load_string)
            .collect::<Result<Vec<_>, _>>()?
    };

    // For now, ignore dirfd and flags - just use the pathname directly
    // Most LTP tests use AT_FDCWD or absolute paths
    let _ = dirfd;
    let _ = flags;

    debug!("sys_execveat <= dirfd: {dirfd}, path: {path:?}, flags: {flags:#x}");

    do_execve(uctx, &path, args, envs)
}

fn do_execve(
    uctx: &mut UserContext,
    path: &str,
    args: Vec<String>,
    envs: Vec<String>,
) -> AxResult<isize> {
    let curr = current();
    let proc_data = &curr.as_thread().proc_data;

    if proc_data.proc.threads().len() > 1
        && !proc_data.proc.threads().is_empty()
    {
        return Err(AxError::WouldBlock);
    }

    let (entry_point, user_stack_base) = {
        let aspace = proc_data.aspace.clone();
        let mut aspace = aspace.lock();
        aspace.clear();
        load_user_app(&mut aspace, None, &args, &envs)?
    };

    drop(proc_data.exe_path.write());
    drop(proc_data.cmdline.write());

    let curr2 = current();
    let proc_data = &curr2.as_thread().proc_data;

    let loc = FS_CONTEXT.lock().resolve(path)?;
    curr2.set_name(loc.name());

    *proc_data.exe_path.write() = loc.absolute_path()?.to_string();
    *proc_data.cmdline.write() = Arc::new(args);

    proc_data.set_heap_top(USER_HEAP_BASE);

    *proc_data.signal.actions.lock() = Default::default();

    curr2.as_thread().set_clear_child_tid(0);

    let mut fd_table = FD_TABLE.write();
    let cloexec_fds = fd_table
        .ids()
        .filter(|it| fd_table.get(*it).unwrap().cloexec)
        .collect::<Vec<_>>();
    for fd in cloexec_fds {
        fd_table.remove(fd);
    }
    drop(fd_table);

    uctx.set_ip(entry_point.as_usize());
    uctx.set_sp(user_stack_base.as_usize());
    Ok(0)
}

